// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.Objects;
import java.util.stream.Stream;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.query.explanation.GenericPlanNode;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

public class LmdbNativeQueryExplanationTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String PLANNED_EXECUTION_ENGINE = "plannedExecutionEngine";
	private static final String PLANNED_EXECUTION_KIND = "plannedExecutionKind";
	private static final String LMDB_NATIVE = "lmdb-native";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI item = vf.createIRI(EX, "Item");
			IRI price = vf.createIRI(EX, "price");
			for (int i = 0; i < 4; i++) {
				IRI subject = vf.createIRI(EX, "item" + i);
				conn.add(subject, RDF.TYPE, item);
				conn.add(subject, price, vf.createLiteral(i));
			}
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void unoptimizedExplanationKeepsNativeMarkerOutOfParsedPlan() {
		Explanation explanation = explain(Explanation.Level.Unoptimized, rowQuery());

		assertNoNativeMarker(explanation);
	}

	@Test
	public void rowNativeEvaluationMarkerAppearsAtAllPostParsedExplanationLevels() {
		for (Explanation.Level level : Stream
				.of(Explanation.Level.Optimized, Explanation.Level.Executed, Explanation.Level.Timed,
						Explanation.Level.Telemetry)
				.toList()) {
			Explanation explanation = explain(level, rowQuery());

			assertNativeMarker(explanation, "row", level.name());
		}
	}

	@Test
	public void aggregateNativeEvaluationMarkerReportsAggregateKind() {
		Explanation explanation = explain(Explanation.Level.Optimized, aggregateQuery());

		assertNativeMarker(explanation, "aggregate", Explanation.Level.Optimized.name());
	}

	@Test
	public void executedAndTelemetryExplanationsShowNativePhysicalPlan() {
		for (Explanation.Level level : Stream.of(Explanation.Level.Executed, Explanation.Level.Telemetry).toList()) {
			Explanation explanation = explain(level, aggregateQuery());

			assertNativeMarker(explanation, "aggregate", level.name());
			assertThat(explanation.toString())
					.as(level.name() + " explanation should show the native physical plan that was executed")
					.contains("nativePhysicalPlan=");
			assertThat(explanation.toJson())
					.as(level.name() + " JSON explanation should show the native physical plan that was executed")
					.contains("\"nativePhysicalPlan\"");
		}
	}

	@Test
	public void telemetryExplanationShowsChunkPipelineEngagement() {
		// ?price is unprojected, so the trailing price pattern becomes a factorized tail branch and the
		// chunk pipeline drives the all-pattern prefix; the telemetry explanation must say so, or silent
		// disqualification regressions stay invisible
		// (generic actual string metrics surface at the Telemetry level by framework design)
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s WHERE { ?s a ex:Item . ?s ex:price ?price }";
		Explanation explanation = explain(Explanation.Level.Telemetry, query);

		assertThat(explanation.toString()).contains("nativeExecutionStrategy=chunkPipeline");
	}

	@Test
	public void telemetryExplanationShowsFactorizedTailEngagement() {
		String query = "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?price) AS ?c) WHERE { ?s a ex:Item . ?s ex:price ?price }";
		Explanation explanation = explain(Explanation.Level.Telemetry, query);

		assertThat(explanation.toString()).contains("nativeExecutionStrategy=factorizedTail");
	}

	@Test
	public void disabledNativeEngineSuppressesNativeExplanationMarker() {
		String previous = System.getProperty(NATIVE_FLAG);
		try {
			System.setProperty(NATIVE_FLAG, "false");

			Explanation explanation = explain(Explanation.Level.Optimized, rowQuery());

			assertNoNativeMarker(explanation);
		} finally {
			restoreProperty(previous);
		}
	}

	private Explanation explain(Explanation.Level level, String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			return conn.prepareTupleQuery(query).explain(level);
		}
	}

	private static String rowQuery() {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s ?price WHERE { ?s a ex:Item ; ex:price ?price }";
	}

	private static String aggregateQuery() {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(*) AS ?count) WHERE { ?s a ex:Item ; ex:price ?price }";
	}

	private static void assertNativeMarker(Explanation explanation, String expectedKind, String description) {
		assertThat(hasPlannedMetric(explanation.toGenericPlanNode(), PLANNED_EXECUTION_ENGINE, LMDB_NATIVE))
				.as(description + " generic plan node should expose the LMDB native marker")
				.isTrue();
		assertThat(hasPlannedMetric(explanation.toGenericPlanNode(), PLANNED_EXECUTION_KIND, expectedKind))
				.as(description + " generic plan node should expose the LMDB native execution kind")
				.isTrue();

		assertThat(explanation.toString()).contains(PLANNED_EXECUTION_ENGINE + "=" + LMDB_NATIVE);
		assertThat(explanation.toString()).contains(PLANNED_EXECUTION_KIND + "=" + expectedKind);
		assertThat(explanation.toJson()).contains("\"" + PLANNED_EXECUTION_ENGINE + "\"");
		assertThat(explanation.toJson()).contains("\"" + PLANNED_EXECUTION_KIND + "\"");
		assertThat(explanation.toDot()).contains(LMDB_NATIVE);
		assertThat(explanation.toDot()).contains(expectedKind);
	}

	private static void assertNoNativeMarker(Explanation explanation) {
		assertThat(explanation.toString()).doesNotContain(PLANNED_EXECUTION_ENGINE);
		assertThat(explanation.toJson()).doesNotContain(PLANNED_EXECUTION_ENGINE);
		assertThat(explanation.toDot()).doesNotContain(LMDB_NATIVE);
		assertThat(hasPlannedMetric(explanation.toGenericPlanNode(), PLANNED_EXECUTION_ENGINE, LMDB_NATIVE))
				.isFalse();
	}

	private static boolean hasPlannedMetric(GenericPlanNode node, String metricName, String metricValue) {
		if (node == null) {
			return false;
		}
		if (Objects.equals(metricValue, node.getStringMetricPlanned(metricName))) {
			return true;
		}
		if (node.getPlans() == null) {
			return false;
		}
		return node.getPlans()
				.stream()
				.anyMatch(child -> hasPlannedMetric(child, metricName, metricValue));
	}

	private static void restoreProperty(String previous) {
		if (previous == null) {
			System.clearProperty(NATIVE_FLAG);
		} else {
			System.setProperty(NATIVE_FLAG, previous);
		}
	}
}
